const upstreamAgentPendingAccounts = `-- name: UpstreamAgentPendingAccounts :many
select a.accountname as upagent,child.accountname as childagent, fo.createdat as ordercreatedat from account a 
	left join account child on a.id=child.upstreamaccount 
	left join franchiseorder fo on fo.accountid=child.id
where fo.status='pending'
and fo.createdat < (select createdat from franchiseorder where id= $1::uuid)
and a.id =(select upstreamaccount from account where id=(select accountid from franchiseorder where id= $1::uuid))
`

type UpstreamAgentPendingAccountsRow struct {
	Upagent        *string          `json:"upagent"`
	Childagent     *string          `json:"childagent"`
	Ordercreatedat pgtype.Timestamp `json:"ordercreatedat"`
}

func (q *Queries) UpstreamAgentPendingAccounts(ctx context.Context, franchiseorderid uuid.UUID) ([]UpstreamAgentPendingAccountsRow, error) {
	rows, err := q.db.Query(ctx, upstreamAgentPendingAccounts, franchiseorderid)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []UpstreamAgentPendingAccountsRow
	for rows.Next() {
		var i UpstreamAgentPendingAccountsRow
		if err := rows.Scan(&i.Upagent, &i.Childagent, &i.Ordercreatedat); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

